import React, { useState } from "react";
import AddTravel from "./AddTravel";
import AddTicket from "./AddTicket";

const AddNew = ({ employee }) => {
  const [selectedType, setSelectedType] = useState(null);

  if (!selectedType) {
    // your two cards UI here, with:
    // onClick={() => setSelectedType("travel")}
    // onClick={() => setSelectedType("ticket")}
  }

  if (selectedType === "travel") {
    return <AddTravel employee={employee} />;
  }

  if (selectedType === "ticket") {
    return <AddTicket employee={employee} />;
  }

  return null;
};

export default AddNew;
